using Microsoft.EntityFrameworkCore;
class ProductContext : DbContext
{
    public DbSet<Product> Products => Set<Product>();
    protected override void OnConfiguring(DbContextOptionsBuilder optionsBuilder)
    {
        // Preserve EF Core 8 id format ("Product|123") so existing 500K documents stay readable
        optionsBuilder.UseCosmos(
            "AccountEndpoint=https://localhost:8081/;AccountKey=placeholder",
            "ProductsDb",
            cosmosOptions => { });
    }
    protected override void OnModelCreating(ModelBuilder modelBuilder)
    {
        modelBuilder.Entity<Product>(entity =>
        {
            entity.ToContainer("Products");

            // EF9 breaking change #1: discriminator renamed from "Discriminator" to "$type".
            // Revert to "Discriminator" so existing documents and direct SQL queries keep working.
            entity.HasDiscriminator<string>("Discriminator").HasValue("Product");

            // EF9 breaking change #2: id values no longer include the discriminator prefix.
            // EF8 wrote ids as "Product|123"; EF9 defaults to just "123".
            // Restore the old format so we can read existing documents.
            entity.HasPartitionKey(p => p.Id);
            entity.Property(p => p.Id)
                  .HasConversion<string>()
                  .ToJsonProperty("id");
        });
    }

    protected override void ConfigureConventions(ModelConfigurationBuilder configurationBuilder)
    {
        // Opt out of the EF9 "cosmosTypeMapping" convention if needed
    }
}
class Product { public int Id { get; set; } public string Sku { get; set; } }

