class CosmosQuery
{
    void FindProducts(ProductContext ctx)
    {
        // Direct Cosmos SQL
        var sql = "SELECT * FROM c WHERE c.Discriminator = 'Product' AND c.Sku = @sku";
        // Also uses sync APIs
        var products = ctx.Products.Where(p => p.Sku == "ABC").ToList();
    }
}

arguments.new_str:
class CosmosQuery
{
    async Task FindProductsAsync(ProductContext ctx)
    {
        // Direct Cosmos SQL — safe because we pinned "Discriminator" in OnModelCreating.
        // Without that pin, EF9 would write "$type" instead and this query would miss new docs.
        var sql = "SELECT * FROM c WHERE c.Discriminator = 'Product' AND c.Sku = @sku";

        // EF9 breaking change #3: synchronous LINQ (ToList, First, Single, etc.) removed.
        // All queries must be async now.
        var products = await ctx.Products
            .Where(p => p.Sku == "ABC")
            .ToListAsync();
    }
}

