using Microsoft.EntityFrameworkCore;
class ProductContext : DbContext
{
    public DbSet<Product> Products => Set<Product>();
    protected override void OnModelCreating(ModelBuilder modelBuilder)
    {
        modelBuilder.Entity<Product>(entity =>
        {
            entity.ToContainer("Products");

            // BREAKING CHANGE #1 — Discriminator property renamed.
            // EF8 stored "Discriminator": "Product".  EF9 defaults to "$type": "Product".
            // Pin to old name so existing 500K documents AND direct SQL queries keep working.
            entity.HasDiscriminator<string>("Discriminator").HasValue("Product");

            // BREAKING CHANGE #2 — Resource id format changed.
            // EF8 generated ids like "Product|123".  EF9 uses just "123".
            // Without mitigation, EF9 cannot find existing documents by key.
            // OPTIONS:
            //   a) Back-fill: update all 500K docs to strip the "Product|" prefix, or
            //   b) Add an explicit string property mapped to the JSON "id" that
            //      preserves the prefix (see README / migration guide).
        });
    }
}

// BREAKING CHANGE #3 — HasIndex not supported for Cosmos DB provider.
// The EF8 call .HasIndex(p => p.Sku) compiled but was ignored at runtime.
// EF9 now throws — removed.

// BREAKING CHANGE #4 — Sync query APIs removed.
// ToList(), First(), Single() etc. throw at runtime. Use async equivalents.

class Product { public int Id { get; set; } public string Sku { get; set; } }

