using Microsoft.EntityFrameworkCore;
class ProductContext : DbContext
{
    public DbSet<Product> Products => Set<Product>();
    protected override void OnConfiguring(DbContextOptionsBuilder optionsBuilder)
    {
        // Preserve EF Core 8 id format ("Product|123") so existing 500K documents stay readable
        optionsBuilder.UseCosmos(
            "AccountEndpoint=https://localhost:8081/;AccountKey=placeholder",
            "ProductsDb",
            cosmosOptions => { });
    }
    protected override void OnModelCreating(ModelBuilder modelBuilder)
    {
        modelBuilder.Entity<Product>(entity =>
        {
            entity.ToContainer("Products");

            // EF9 breaking change #1: discriminator renamed from "Discriminator" to "$type".
            // Revert to "Discriminator" so existing documents and direct SQL queries keep working.
            entity.HasDiscriminator<string>("Discriminator").HasValue("Product");

